sections.body:
- Install the MongoDB Node.js Driver.

  For installation instructions, see the
  [MongoDB Node.js Driver documentation](node).

- Create the index.

  autocomplete

  Create a file named `create_auto_complete_index.js` and paste the following code:

  ```javascript
  const { MongoClient } = require("mongodb");

  // connect to your Atlas deployment
  const uri =  "<connection-string>";

  const client = new MongoClient(uri);

  async function run() {
    try {

      // set namespace
      const database = client.db("sample_mflix");
      const collection = database.collection("movies");

      // define your MongoDB Search index
      const index = {
        name: "partial-match-tutorial-autocomplete",
        definition: {
          /* search index definition fields */
          "mappings": {
            "dynamic": false,
            "fields": {
              "title": {
                "type": "autocomplete",
                "analyzer": "lucene.standard",
                "tokenization": "edgeGram",
                "minGrams": 3,
                "maxGrams": 5,
                "foldDiacritics": false
              }
            }
          }
        }
      }

      // run the helper method
      const result = await collection.createSearchIndex(index);
      console.log("New index name: " + result);
    } finally {
      await client.close();
    }
  }

  run().catch(console.dir);
  ```

  string

  Create a file named `create_string_index.js` and paste the following code:

  ```javascript
  const { MongoClient } = require("mongodb");

  // connect to your Atlas deployment
  const uri =  "<connection-string>";

  const client = new MongoClient(uri);

  async function run() {
    try {

      // set namespace
      const database = client.db("sample_mflix");
      const collection = database.collection("movies");

      // define your MongoDB Search index
      const index = {
        name: "partial-match-tutorial",
        definition: {
          /* search index definition fields */
          "mappings": {
            "dynamic": false,
            "fields": {
              "title": {
                "type": "string",
              }
            }
          }
        }
      }

      // run the helper method
      const result = await collection.createSearchIndex(index);
      console.log("New index name: " + result);
    } finally {
      await client.close();
    }
  }

  run().catch(console.dir);
  ```

- Run the program.

  ```shell
  node create_auto_complete_index.js
  # or
  node create_string_index.js
  ```

