                var result = collection.Aggregate<BsonDocument>(pipeline);

                // Print results
                await result.ForEachAsync(doc => Console.WriteLine(doc.ToJson()));
            }
            catch (Exception ex)
            {
                Console.WriteLine($"Error: {ex.Message}");
            }
        }
    }
}

